import './Navigation.scss';

import { IconButton } from ':components/IconButton';
import { Typography } from ':components/Typography';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

export interface NavigationProps {
	onClickNext: (event) => void;
	onClickPrev: (event) => void;
	max: number;
	value: number;
}

export const Navigation = ({ max, value, onClickNext, onClickPrev }: NavigationProps) => (
	<div className="dsb_preview__navigation">
		<IconButton variant="base" iconName={Icons.ArrowLeft} onClick={onClickPrev} disabled={value === 1} />
		<Typography variant="body2" className="dsb_preview__navigation__text">
			{value} из {max}
		</Typography>
		<IconButton variant="base" iconName={Icons.ArrowRight} onClick={onClickNext} disabled={max === value} />
	</div>
);
